import React, { useState, useEffect } from 'react';
import { getNotificationsByUser } from '../../api/api';
import { useAuth } from '../../context/AuthContext';
import toast from 'react-hot-toast';

const NOTIFY_ICONS = { BOOKING:'🎟', CANCELLATION:'❌', PAYMENT:'💳', REMINDER:'⏰' };
const NOTIFY_STYLES = {
  BOOKING:      { bg:'#f0faf6', border:'rgba(26,143,99,0.2)', color:'var(--green)', leftBorder:'var(--green)' },
  CANCELLATION: { bg:'#fff8f5', border:'rgba(224,92,42,0.2)', color:'var(--accent)', leftBorder:'var(--accent)' },
  PAYMENT:      { bg:'#f0f6ff', border:'rgba(37,99,168,0.2)', color:'var(--blue)',  leftBorder:'var(--blue)' },
  REMINDER:     { bg:'#fffbf0', border:'rgba(201,125,26,0.2)', color:'var(--gold)', leftBorder:'var(--gold)' },
};

const NotificationsPage = () => {
  const { user } = useAuth();
  const [notifications, setNotifications] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('ALL');

  useEffect(()=>{
    const load = async ()=>{
      try {
        const res = await getNotificationsByUser(user.userId);
        const sorted = (res.data.data||[]).sort((a,b)=>new Date(b.sentTime)-new Date(a.sentTime));
        setNotifications(sorted);
      } catch { toast.error('Failed to load notifications'); }
      finally { setLoading(false); }
    };
    load();
  },[]);

  const types = ['ALL','BOOKING','PAYMENT','CANCELLATION','REMINDER'];
  const filtered = filter==='ALL' ? notifications : notifications.filter(n=>n.notifyType===filter);

  return (
    <div style={{ background:'var(--bg-secondary)', minHeight:'100vh' }}>
      <div className="container" style={{ paddingTop:'36px', paddingBottom:'48px' }}>
        <div className="page-header">
          <h1 className="page-title">Notifications</h1>
          <p className="page-subtitle">{notifications.length} total notifications</p>
        </div>

        <div className="tabs">
          {types.map(t=>(
            <button key={t} className={`tab-btn ${filter===t?'active':''}`} onClick={()=>setFilter(t)}>
              {NOTIFY_ICONS[t]||'🔔'} {t}
            </button>
          ))}
        </div>

        {loading ? (
          <div className="loading-center"><div className="spinner" /></div>
        ) : filtered.length===0 ? (
          <div className="empty-state"><div className="empty-state-icon">🔔</div><h3>No Notifications</h3></div>
        ) : (
          <div style={{ display:'flex', flexDirection:'column', gap:'10px' }}>
            {filtered.map(n=>{
              const s = NOTIFY_STYLES[n.notifyType]||{ bg:'white', border:'var(--border)', color:'var(--text-muted)', leftBorder:'var(--border)' };
              return (
                <div key={n.notificationId} style={{ background:s.bg, border:`1.5px solid ${s.border}`, borderLeft:`4px solid ${s.leftBorder}`, borderRadius:'var(--radius)', padding:'16px 20px', boxShadow:'var(--shadow-sm)' }}>
                  <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', gap:'12px' }}>
                    <div style={{ flex:1 }}>
                      <div style={{ display:'flex', gap:'8px', alignItems:'center', marginBottom:'6px' }}>
                        <span style={{ fontSize:'18px' }}>{NOTIFY_ICONS[n.notifyType]||'🔔'}</span>
                        <span style={{ fontSize:'11px', fontWeight:700, letterSpacing:'0.5px', textTransform:'uppercase', color:s.color }}>{n.notifyType}</span>
                        <span className={`badge ${n.deliveryState==='SENT'?'badge-success':n.deliveryState==='FAILED'?'badge-danger':'badge-warning'}`} style={{ fontSize:'10px' }}>{n.deliveryState}</span>
                      </div>
                      <p style={{ fontSize:'14px', color:'var(--text-primary)', lineHeight:1.6, fontWeight:500 }}>{n.message}</p>
                    </div>
                    <div style={{ fontSize:'12px', color:'var(--text-muted)', flexShrink:0, fontWeight:500 }}>
                      {n.sentTime ? new Date(n.sentTime).toLocaleString('en-IN',{day:'2-digit',month:'short',hour:'2-digit',minute:'2-digit'}) : '-'}
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};
export default NotificationsPage;
